// Ler o conteúdo atual do index.php
$indexContent = file_get_contents('index.php');

// Encontrar a posição do final do array iconMap
$iconMapStart = strpos($indexContent, '$iconMap = [');
$iconMapEnd = strpos($indexContent, '];', $iconMapStart);

if ($iconMapStart === false || $iconMapEnd === false) {
    echo "❌ Erro: Não foi possível encontrar o array iconMap no index.php\n";
    exit(1);
}

// Extrair o conteúdo atual do iconMap
$beforeIconMap = substr($indexContent, 0, $iconMapEnd);
$afterIconMap = substr($indexContent, $iconMapEnd);

// Adicionar os novos ícones
$newIcons = '';
foreach ($priorityIcons as $iconClass => $iconSvg) {
    // Verificar se o ícone já existe
    if (strpos($beforeIconMap, "'$iconClass'") === false) {
        $newIcons .= "        '$iconClass' => '$iconSvg',\n";
        echo "✅ Adicionando: $iconClass\n";
    } else {
        echo "⚠️  Já existe: $iconClass\n";
    }
}

if ($newIcons) {
    // Inserir os novos ícones antes do fechamento do array
    $newContent = $beforeIconMap . "\n" . $newIcons . $afterIconMap;
    
    // Salvar o arquivo
    if (file_put_contents('index.php', $newContent)) {
        echo "\n✅ SUCESSO: Ícones adicionados ao index.php!\n";
        echo "Total de ícones adicionados: " . count(array_filter($priorityIcons, function($iconClass) use ($beforeIconMap) {
            return strpos($beforeIconMap, "'$iconClass'") === false;
        }, ARRAY_FILTER_USE_KEY)) . "\n";
    } else {
        echo "\n❌ ERRO: Não foi possível salvar o arquivo index.php\n";
    }
} else {
    echo "\n⚠️  Nenhum ícone novo foi adicionado (todos já existem)\n";
}
?>